changeSet.sql:
-- Drop the existing ivfflat index (required before column change)
DROP INDEX IF EXISTS idx_cv_embedding_ivfflat;

-- Remove all existing embeddings (Gemini 768-dim vectors, incompatible with bge-m3)
TRUNCATE TABLE cv_embedding;

-- Replace embedding column with vector(1024)
ALTER TABLE cv_embedding DROP COLUMN embedding;
ALTER TABLE cv_embedding ADD COLUMN embedding vector(1024) NOT NULL;

-- Recreate ivfflat index with cosine ops (bge-m3 is trained for cosine similarity)
CREATE INDEX IF NOT EXISTS idx_cv_embedding_ivfflat
    ON cv_embedding USING ivfflat (embedding vector_cosine_ops) WITH (lists = 100);
